shellupdate.__example:
local sysutils = require "sysutils"

-- Register file association ".test" with the application "test.exe"
sys.registry.write("HKEY_CURRENT_USER", "Software\\Classes\\.test", nil, "test");
sys.registry.write("HKEY_CURRENT_USER", "Software\\Classes\\test", nil, "test file");
sys.registry.write("HKEY_CURRENT_USER", "Software\\Classes\\lua\\shell\\open\\command", nil, '"c:\\test.exe" "%1"');

-- Notify the Shell that a change occured (no need to logoff the current session)
sysutils.shellupdate()
